const e=JSON.parse(`[{"q":"Gymnosperms are called naked seeded plants because","options":["They have no seeds","Their seeds are not enclosed in fruit","Their seeds have no seed coat","They have no flowers"],"answer":1,"explanation":"Gymnosperms are called naked seeded plants because their ovules and seeds are not enclosed in an ovary/fruit — they are exposed on the surface of scales."},{"q":"The tallest gymnosperm is","options":["Cycas","Pinus","Sequoia","Gnetum"],"answer":2,"explanation":"Sequoia sempervirens (coastal redwood) is the tallest gymnosperm and tallest tree in the world, reaching over 115 meters."},{"q":"Cycas is commonly called","options":["Pine","Sago palm","Cedar","Spruce"],"answer":1,"explanation":"Cycas revoluta is commonly called sago palm. Despite looking like a palm, it is a gymnosperm not a monocot."},{"q":"Which gymnosperm is called a living fossil?","options":["Pinus","Cycas","Ginkgo","Ephedra"],"answer":2,"explanation":"Ginkgo biloba is called a living fossil because it has remained unchanged for over 200 million years and is the sole survivor of its group."},{"q":"Resin and turpentine are obtained from","options":["Cycas","Pinus","Gnetum","Ephedra"],"answer":1,"explanation":"Resin and turpentine are obtained from Pinus (pine). Resin canals in pine wood produce these commercially important products."},{"q":"The drug ephedrine is obtained from","options":["Cycas","Pinus","Gnetum","Ephedra"],"answer":3,"explanation":"Ephedrine is a drug obtained from Ephedra (a gymnosperm). It is used to treat asthma, bronchitis and nasal congestion."},{"q":"Coralloid roots in Cycas are associated with","options":["Water absorption","Nitrogen fixation by Anabaena","Food storage","Anchorage"],"answer":1,"explanation":"Coralloid roots in Cycas contain Anabaena (cyanobacterium) that fixes atmospheric nitrogen. They are short, branched and coral-like."},{"q":"In gymnosperms the female gametophyte is","options":["Free living and independent","Retained inside megasporangium","A prothallus","Absent"],"answer":1,"explanation":"In gymnosperms the female gametophyte is retained inside the megasporangium (nucellus) and is entirely dependent on the sporophyte."},{"q":"Pinus belongs to class","options":["Cycadopsida","Coniferopsida","Gnetopsida","Ginkgopsida"],"answer":1,"explanation":"Pinus belongs to class Coniferopsida (conifers). Conifers are the largest group of gymnosperms and include pine, fir, spruce and cedar."},{"q":"The leaves of Pinus are called","options":["Fronds","Needles","Scales","Pinnae"],"answer":1,"explanation":"Pinus has needle-like leaves that are adapted to reduce water loss. The needles are borne in clusters called fascicles."},{"q":"The male cone of Pinus produces","options":["Megaspores","Microspores (pollen)","Seeds","Ovules"],"answer":1,"explanation":"The male cone (microstrobilus) of Pinus bears microsporophylls which produce microspores (pollen grains) by meiosis."},{"q":"Which of the following is a gymnosperm?","options":["Mango","Cycas","Rose","Wheat"],"answer":1,"explanation":"Cycas is a gymnosperm with naked seeds. Mango, rose and wheat are angiosperms with seeds enclosed in fruit."},{"q":"Fertilization in gymnosperms is","options":["Hydrophilous","Entomophilous","Anemophilous (wind pollination)","Ornithophilous"],"answer":2,"explanation":"Gymnosperms are wind pollinated (anemophilous). They produce large amounts of light pollen that is carried by wind to female cones."},{"q":"The ovule in gymnosperms is","options":["Enclosed in ovary","Naked on megasporophyll","Inside fruit","Underground"],"answer":1,"explanation":"In gymnosperms the ovules are naked — they are borne directly on the surface of megasporophylls (scales) without an enclosing ovary."},{"q":"Ginkgo biloba is used medicinally for","options":["Asthma","Memory enhancement and circulation","Diabetes","Malaria"],"answer":1,"explanation":"Ginkgo biloba extract is used medicinally to enhance memory, improve blood circulation and treat dementia and Alzheimer's disease."},{"q":"The woody cone of conifers is called","options":["Strobilus","Sorus","Sporocarp","Capitulum"],"answer":0,"explanation":"The cone (strobilus) is the reproductive structure of conifers. Male cones produce pollen and female cones bear ovules and seeds."},{"q":"Which gymnosperm has vessels in xylem?","options":["Pinus","Cycas","Gnetum","Ginkgo"],"answer":2,"explanation":"Gnetum is unique among gymnosperms in having vessels in xylem like angiosperms. Other gymnosperms have only tracheids."},{"q":"The largest ovule in plant kingdom belongs to","options":["Pinus","Cycas","Sequoia","Ginkgo"],"answer":1,"explanation":"Cycas has the largest ovule in the plant kingdom. The ovule of Cycas can be as large as a plum."},{"q":"Sago is obtained from","options":["Pinus","Cycas","Gnetum","Ephedra"],"answer":1,"explanation":"Sago (starch) is obtained from the pith of Cycas stem. It is used as food in some parts of Asia."},{"q":"The wood of gymnosperms is called","options":["Hardwood","Softwood","Heartwood","Sapwood"],"answer":1,"explanation":"Gymnosperm wood is called softwood because it lacks vessels and is composed mainly of tracheids. Angiosperm wood is hardwood."},{"q":"Double fertilization occurs in","options":["Gymnosperms","Angiosperms","Pteridophytes","Bryophytes"],"answer":1,"explanation":"Double fertilization is unique to angiosperms. Gymnosperms have simple fertilization — one sperm fuses with egg to form zygote only."},{"q":"The microsporophylls in Pinus are arranged in","options":["Female cone","Male cone","Vegetative shoot","Root"],"answer":1,"explanation":"Microsporophylls bearing pollen sacs (microsporangia) are arranged spirally in male cone (microstrobilus) of Pinus."},{"q":"Cycas is dioecious because","options":["It has both male and female cones on same plant","Male and female cones are on separate plants","It has no cones","It has bisexual cones"],"answer":1,"explanation":"Cycas is dioecious — male plants bear microsporophylls (loose cone-like) and female plants bear megasporophylls separately."},{"q":"Which of the following is the connecting link between gymnosperms and angiosperms?","options":["Cycas","Pinus","Gnetum","Ephedra"],"answer":2,"explanation":"Gnetum is considered a connecting link between gymnosperms and angiosperms because it has broad leaves, vessels in xylem and net-like venation."},{"q":"Paper is commercially obtained from","options":["Cycas","Conifers like Abies and Picea","Ginkgo","Ephedra"],"answer":1,"explanation":"Paper is commercially obtained from conifers like Abies (fir) and Picea (spruce). Their wood pulp is the main raw material for paper industry."},{"q":"The oldest living gymnosperm is","options":["Cycas","Pinus longaeva","Sequoia","Ginkgo"],"answer":1,"explanation":"Pinus longaeva (bristlecone pine) is the oldest living gymnosperm and oldest known living tree, with some specimens over 5000 years old."},{"q":"Archegonia in gymnosperms are found in","options":["Male cone","Female gametophyte","Pollen grain","Seed coat"],"answer":1,"explanation":"Archegonia are found in the female gametophyte (endosperm) of gymnosperms. Each archegonium contains an egg cell for fertilization."},{"q":"The embryo in gymnosperm seed is surrounded by","options":["Fruit wall","Endosperm (female gametophyte)","Perisperm","Cotyledons only"],"answer":1,"explanation":"The embryo in gymnosperm seed is surrounded by endosperm derived from the female gametophyte tissue. This provides nutrition to the embryo."},{"q":"Pollen grains of Pinus have","options":["No wings","Two air bladders (wings)","Four wings","One wing"],"answer":1,"explanation":"Pollen grains of Pinus have two air bladders (wings/sacci) that help in wind dispersal. This is an adaptation for anemophily."},{"q":"The number of cotyledons in Pinus is","options":["One","Two","Many (polyembryony)","None"],"answer":2,"explanation":"Pinus is polycotyolous — it has many cotyledons (8-18). This is a characteristic feature of gymnosperms unlike monocots (1) and dicots (2)."},{"q":"Which gymnosperm is used as Christmas tree?","options":["Cycas","Abies","Ginkgo","Ephedra"],"answer":1,"explanation":"Abies (fir) and Picea (spruce) are commonly used as Christmas trees. Their conical shape and evergreen needles make them popular."},{"q":"Transfusion tissue in gymnosperm leaf helps in","options":["Photosynthesis","Transport of water and food between mesophyll and vascular bundle","Gas exchange","Mechanical support"],"answer":1,"explanation":"Transfusion tissue is unique to gymnosperms. It surrounds the vascular bundle and helps in lateral transport of water and food to and from mesophyll."},{"q":"The megasporophyll of Cycas is","options":["Leaf-like with ovules on margins","Scale-like in compact cone","Needle-like","Absent"],"answer":0,"explanation":"The megasporophyll of Cycas is leaf-like (pinnate) with 2-8 ovules on its margins. It is loosely arranged unlike the compact cones of other gymnosperms."},{"q":"Gymnosperms first appeared in","options":["Cambrian period","Devonian period","Jurassic period","Cretaceous period"],"answer":1,"explanation":"Gymnosperms first appeared in the Devonian period about 385 million years ago. They dominated the Mesozoic era (age of dinosaurs)."},{"q":"Which of the following gymnosperm has motile sperms?","options":["Pinus","Abies","Cycas and Ginkgo","Ephedra"],"answer":2,"explanation":"Cycas and Ginkgo have large motile (flagellated) sperms — a primitive feature linking them to pteridophytes. Other gymnosperms have non-motile sperms."},{"q":"The endosperm of gymnosperms is","options":["Triploid like angiosperms","Haploid female gametophyte tissue","Diploid","Absent"],"answer":1,"explanation":"The endosperm of gymnosperms is the haploid female gametophyte tissue formed before fertilization. Unlike angiosperms where endosperm is triploid and formed after fertilization."},{"q":"Sunken stomata in gymnosperm leaves is an adaptation for","options":["Increasing photosynthesis","Reducing water loss","Increasing gas exchange","Absorbing more CO2"],"answer":1,"explanation":"Sunken stomata in gymnosperm leaves (especially conifers) reduce water loss by reducing air movement around stomata — an adaptation to cold dry conditions."},{"q":"Which of the following is incorrect about gymnosperms?","options":["They have naked seeds","They have double fertilization","They are vascular plants","They produce pollen"],"answer":1,"explanation":"Double fertilization does NOT occur in gymnosperms. It is a unique feature of angiosperms. Gymnosperms have simple fertilization."},{"q":"The male gametophyte of gymnosperm is represented by","options":["Antheridium","Pollen grain","Microspore mother cell","Microsporophyll"],"answer":1,"explanation":"The pollen grain is the male gametophyte of gymnosperms. It consists of few cells including tube cell and generative cell."},{"q":"Polyembryony is common in","options":["Bryophytes","Pteridophytes","Gymnosperms","Angiosperms"],"answer":2,"explanation":"Polyembryony (formation of multiple embryos in one seed) is common in gymnosperms like Pinus. It occurs due to cleavage of early embryo."},{"q":"Which of the following is an evergreen gymnosperm?","options":["Ginkgo","Larix","Pinus","Metasequoia"],"answer":2,"explanation":"Pinus is an evergreen gymnosperm that retains its needle-like leaves throughout the year. Ginkgo and Larix are deciduous gymnosperms."},{"q":"The microsporangium of Pinus is also called","options":["Pollen sac","Ovule","Seed","Anther"],"answer":0,"explanation":"The microsporangium in Pinus male cone is also called pollen sac. Two pollen sacs are present on the lower surface of each microsporophyll."},{"q":"Cedar wood oil used in perfumery is obtained from","options":["Pinus","Cedrus","Abies","Cupressus"],"answer":1,"explanation":"Cedar wood oil used in perfumery and as insect repellent is obtained from Cedrus (cedar) wood. Cedrus deodara is the national tree of Pakistan."},{"q":"Gymnosperms are","options":["Non-vascular seedless plants","Vascular seed-bearing plants without fruit","Vascular plants with fruit","Non-vascular seed-bearing plants"],"answer":1,"explanation":"Gymnosperms are vascular seed-bearing plants that do not produce fruits. Their seeds are naked (not enclosed in fruit)."},{"q":"Which of the following has the largest male gamete in plant kingdom?","options":["Pinus","Cycas","Ginkgo","Ephedra"],"answer":1,"explanation":"Cycas has the largest male gametes (sperms) in the plant kingdom. They are large, multiciliate and motile."}]`);export{e as default};
